// Get input data (first item in n8n input)
const items = $input.item.json.data;

// Combine all "text" fields into one string
let combined = items
  .map(chunk => chunk.text || "") // safely get text
  .join(" ")                      // join with spaces
  .trim();

// Return as a single item
return [{
  json: {
    combinedText: combined
  }
}];
